+fn caller_read_c_string(
+    caller: &mut Caller<'_, WasmHostData>,
+    offset: usize,
+) -> Result<String, String> {
+    let memory = caller_memory(caller)?;
+    let bytes = memory.data(&mut *caller);
+    let mut end = offset;
+    while end < bytes.len() && bytes[end] != 0 {
+        end += 1;
+    }
+    if end >= bytes.len() {
